'use client'

import { useState } from "react"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Settings, User, LogOut } from "lucide-react"
import { createClient } from "@/lib/supabase/client"
import { useRouter } from "next/navigation"

interface SettingsClientProps {
    initialProfile: any
}

export default function SettingsClient({ initialProfile }: SettingsClientProps) {
    const [profile, setProfile] = useState(initialProfile)
    const router = useRouter()
    const supabase = createClient()

    const handleSignOut = async () => {
        await supabase.auth.signOut()
        router.refresh()
        router.push('/login')
    }

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-foreground flex items-center gap-2">
                        <Settings className="h-7 w-7 text-primary" />
                        Configurações
                    </h1>
                    <p className="text-muted-foreground">
                        Gerencie suas preferências e conta
                    </p>
                </div>
            </div>

            <div className="grid gap-6 md:grid-cols-2">
                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <User className="h-5 w-5" /> Perfil
                        </CardTitle>
                        <CardDescription>Suas informações pessoais</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="space-y-2">
                            <Label>Nome Completo</Label>
                            <Input value={profile?.full_name || ''} readOnly />
                        </div>
                        <div className="space-y-2">
                            <Label>Email</Label>
                            <Input value={profile?.email || ''} readOnly />
                        </div>
                        <div className="space-y-2">
                            <Label>Função</Label>
                            <Input value={profile?.role || ''} readOnly className="capitalize" />
                        </div>

                        <Button variant="destructive" className="w-full mt-4" onClick={handleSignOut}>
                            <LogOut className="mr-2 h-4 w-4" /> Sair da Conta
                        </Button>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader>
                        <CardTitle>Preferências do Sistema</CardTitle>
                        <CardDescription>Personalize sua experiência</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4 text-muted-foreground text-sm">
                        <p>Opções de tema, notificações e integrações em breve.</p>
                    </CardContent>
                </Card>
            </div>
        </div>
    )
}
